   783→            len = index-first;
   784→            if (len > HLL_SPARSE_ZERO_MAX_LEN) {
   785→                HLL_SPARSE_XZERO_SET(n,len);
   786→                n += 2;
   787→            } else {
   788→                HLL_SPARSE_ZERO_SET(n,len);
   789→                n++;
   790→            }
   791→        }
